import argparse
import json
import os
import numpy as np
import heapq
from collections import deque
from cogniplan_env import ExplorationEnv


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n["coords"])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class SimpleGreedyPlanner:
    def __init__(self, dist_denom=1.0, visited_penalty=0.15, reverse_penalty=0.4,
                 history_penalty=0.65, history_len=12):
        self.dist_denom = dist_denom
        self.visited_penalty = visited_penalty
        self.reverse_penalty = reverse_penalty
        self.history_penalty = history_penalty
        self.history_len = history_len
        self.reset()

    def reset(self):
        self.step_count = 0
        self.history = deque(maxlen=self.history_len)
        self.prev_pos = None

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs["robot_pos"], dtype=float)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        nb_to_node = {}
        node_to_nb = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(round_coord(nb))
            if j is not None:
                nb_to_node[idx] = j
                node_to_nb[j] = idx

        first_step = {}
        for j in range(N):
            if dist[j] == float('inf') or prev[j] is None:
                continue
            cur = j
            depth = 0
            while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                cur = prev[cur]
                depth += 1
            if prev[cur] == r_idx and cur in node_to_nb:
                first_step[j] = node_to_nb[cur]

        remaining_steps = 128 - self.step_count

        reverse_idx = None
        if self.prev_pos is not None:
            prev_vec = robot_pos - np.array(self.prev_pos, dtype=float)
            prev_norm = np.linalg.norm(prev_vec)
            if prev_norm > 0.01:
                best_dot = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_vec = np.array(nb, dtype=float) - robot_pos
                    dot = np.dot(prev_vec, nb_vec)
                    if dot < best_dot:
                        best_dot = dot
                        reverse_idx = idx

        best_score = -float('inf')
        best_nb_idx = None

        for j in range(N):
            if j not in first_step:
                continue
            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue
            d = dist[j]
            score = utility / (d + self.dist_denom)
            if nodes[j].get("visited", False):
                score *= self.visited_penalty
            if j in self.history:
                score *= self.history_penalty
            idx = first_step[j]
            if idx == reverse_idx:
                score *= self.reverse_penalty
            est_steps = max(d / 3.2, 1.0)
            if est_steps > remaining_steps:
                continue
            if score > best_score + 1e-12:
                best_score = score
                best_nb_idx = idx

        if best_nb_idx is None:
            for j in range(N):
                if j not in first_step:
                    continue
                if nodes[j].get("visited", False):
                    continue
                d = dist[j]
                score = 1.0 / (d + self.dist_denom)
                if j in self.history:
                    score *= self.history_penalty
                idx = first_step[j]
                if idx == reverse_idx:
                    score *= self.reverse_penalty
                if score > best_score + 1e-12:
                    best_score = score
                    best_nb_idx = idx

        if best_nb_idx is None and frontiers:
            frontier_pts = np.array(frontiers, dtype=float)
            best_f_dist = float('inf')
            best_f_j = None
            for j in range(N):
                if j not in first_step:
                    continue
                node_coords = np.array(nodes[j]["coords"], dtype=float)
                f_dists = np.linalg.norm(frontier_pts - node_coords, axis=1)
                min_f_dist = np.min(f_dists)
                if min_f_dist < best_f_dist:
                    best_f_dist = min_f_dist
                    best_f_j = j
            if best_f_j is not None:
                best_nb_idx = first_step[best_f_j]

        if best_nb_idx is None:
            best_nb_idx = 0 if neighbors else None

        if best_nb_idx is not None:
            target = tuple(neighbors[best_nb_idx])
            j = coord_to_idx.get(round_coord(target))
            if j is not None:
                self.history.append(j)
            self.prev_pos = tuple(robot_pos)
            return target
        return None


class ImprovedPlanner(SimpleGreedyPlanner):
    pass


def run_episode(env, planner):
    planner.reset()
    obs = env.reset()
    for step in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done", False):
            break
    return env.get_metrics()


def load_checkpoint(checkpoint_dir):
    ckpt_path = os.path.join(checkpoint_dir, "policy.pt")
    if os.path.exists(ckpt_path):
        import torch
        return torch.load(ckpt_path, map_location="cpu")
    return None


def load_episodes(data_path):
    eval_config_path = os.path.join(data_path, "eval_config.json")
    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path, 'r') as f:
            config = json.load(f)
        if isinstance(config, list):
            episodes = config
        elif isinstance(config, dict):
            if "episodes" in config:
                episodes = config["episodes"]
            elif "maps" in config:
                episodes = [{"map_path": m, "env_type": "unknown"} for m in config["maps"]]
    if not episodes:
        maps_dir = os.path.join(data_path, "maps_eval")
        if os.path.isdir(maps_dir):
            for env_type in ["room", "tunnel", "outdoor"]:
                type_dir = os.path.join(maps_dir, env_type)
                if os.path.isdir(type_dir):
                    for fname in sorted(os.listdir(type_dir)):
                        if fname.endswith(".png"):
                            episodes.append({
                                "map_path": os.path.join("maps_eval", env_type, fname),
                                "env_type": env_type
                            })
    return episodes


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    load_checkpoint(args.checkpoint)
    episodes = load_episodes(args.data_path)

    planner = SimpleGreedyPlanner(
        dist_denom=1.0,
        visited_penalty=0.15,
        reverse_penalty=0.4,
        history_penalty=0.65,
        history_len=12
    )

    per_episode = []
    total_explored = 0.0
    total_success = 0
    success_distances = []
    per_type = {}

    for ep in episodes:
        map_path = ep.get("map_path", "")
        env_type = ep.get("env_type", "unknown")
        full_map_path = os.path.join(args.data_path, map_path)
        if not os.path.exists(full_map_path):
            if os.path.exists(map_path):
                full_map_path = map_path
            else:
                continue

        env = ExplorationEnv(map_path=full_map_path)
        metrics = run_episode(env, planner)

        explored_rate = float(metrics.get("explored_rate", 0.0))
        travel_distance = float(metrics.get("travel_distance", 0.0))
        success = 1 if metrics.get("success", False) else 0

        total_explored += explored_rate
        total_success += success
        if success:
            success_distances.append(travel_distance)

        per_episode.append({
            "map_path": map_path,
            "env_type": env_type,
            "success": success,
            "travel_distance": travel_distance,
            "explored_rate": explored_rate
        })

        if env_type not in per_type:
            per_type[env_type] = {"explored": [], "distances": [], "successes": []}
        per_type[env_type]["explored"].append(explored_rate)
        per_type[env_type]["distances"].append(travel_distance)
        per_type[env_type]["successes"].append(success)

    total_episodes = len(per_episode)
    explored_rate = total_explored / total_episodes if total_episodes > 0 else 0.0
    success_rate = total_success / total_episodes if total_episodes > 0 else 0.0
    travel_distance = sum(success_distances) / len(success_distances) if success_distances else 0.0

    per_type_out = {}
    for env_type, data in per_type.items():
        s = sum(data["successes"])
        n = len(data["successes"])
        d = [data["distances"][i] for i in range(n) if data["successes"][i]]
        per_type_out[env_type] = {
            "explored_rate": sum(data["explored"]) / n,
            "travel_distance": sum(d) / len(d) if d else 0.0,
            "success_rate": s / n
        }

    output = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type_out,
        "total_episodes": total_episodes
    }

    out_dir = os.path.dirname(args.output)
    if out_dir:
        os.makedirs(out_dir, exist_ok=True)
    with open(args.output, 'w') as f:
        json.dump(output, f, indent=2)


if __name__ == "__main__":
    main()
